func tableCellClass(size TableSize) string {
	switch size {
	case TableSizeSmall:
		return "px-3 py-1.5 align-middle"
	case TableSizeLarge:
		return "px-6 py-4 align-middle"
	default: // medium
		return "px-4 py-3 align-middle"
	}
}

func tableHeadCellClass(size TableSize) string {
	switch size {
	case TableSizeSmall:
		return "px-3 py-2 text-left text-xs font-semibold uppercase tracking-wide text-secondary"
	case TableSizeLarge:
		return "px-6 py-4 text-left text-xs font-semibold uppercase tracking-wide text-secondary"
	default:
		return "px-4 py-3 text-left text-xs font-semibold uppercase tracking-wide text-secondary"
	}
}

func switchToEditMode(rowID string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_switchToEditMode_a840`,
		Function: `function __templ_switchToEditMode_a840(rowID){const row = document.getElementById("row-" + rowID);
	if (!row) return;
	// Ask HTMX to swap in the edit version via a custom event,
	// OR use a simple JS approach: toggle a data attribute and rely on CSS.
	// Here we use a lightweight vanilla approach – dispatch a custom event
	// that the server can respond to, or swap content directly.
	//
	// If using HTMX server-side swap, replace the body below with:
	//   htmx.trigger(row, "edit");
	//
	// For a fully client-side demo without a server round-trip we toggle
	// every <td> between its display text and an <input>.
	row.querySelectorAll("td[data-key]").forEach(td => {
		const key   = td.dataset.key;
		const value = td.dataset.value || td.textContent.trim();
		const type  = td.dataset.type  || "text";

		if (type === "select") {
			const opts = JSON.parse(td.dataset.options || "[]");
			let html = ` + "`" + `<select name="${key}" class="w-full rounded-md border border-primary px-2 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-primary-300">` + "`" + `;
			opts.forEach(o => {
				const sel = o.value === value ? " selected" : "";
				html += ` + "`" + `<option value="${o.value}"${sel}>${o.label}</option>` + "`" + `;
			});
			html += "</select>";
			td.innerHTML = html;
		} else if (type === "checkbox") {
			const checked = (value === "true" || value === "1" || value === "on") ? " checked" : "";
			td.innerHTML = ` + "`" + `<input type="checkbox" name="${key}" value="true"${checked} class="rounded border-primary text-primary focus:ring-primary-300" />` + "`" + `;
		} else {
			td.innerHTML = ` + "`" + `<input type="${type}" name="${key}" value="${value}" class="w-full rounded-md border border-primary px-2 py-1 text-sm focus:outline-none focus:ring-2 focus:ring-primary-300" />` + "`" + `;
		}
	});

	// Swap action buttons
	const actions = row.querySelector("[data-actions='view']");
	if (actions) actions.style.display = "none";
	const editActions = row.querySelector("[data-actions='edit']");
	if (editActions) editActions.style.display = "flex";

	row.classList.add("bg-primary-light/20", "ring-2", "ring-inset", "ring-primary/40");
}`,
		Call:       templ.SafeScript(`__templ_switchToEditMode_a840`, rowID),
		CallInline: templ.SafeScriptInline(`__templ_switchToEditMode_a840`, rowID),
	}
}

func switchToViewMode(rowID string) templ.ComponentScript {
	return templ.ComponentScript{
		Name: `__templ_switchToViewMode_ff1e`,
		Function: `function __templ_switchToViewMode_ff1e(rowID){const row = document.getElementById("row-" + rowID);
	if (!row) return;

	row.querySelectorAll("td[data-key]").forEach(td => {
		const input = td.querySelector("input, select, textarea");
		if (input) {
			const display = td.dataset.display || (input.type === "checkbox" ? (input.checked ? "true" : "false") : input.value);
			td.innerHTML = display;
		}
	});

	const actions = row.querySelector("[data-actions='view']");
	if (actions) actions.style.display = "flex";
	const editActions = row.querySelector("[data-actions='edit']");
	if (editActions) editActions.style.display = "none";

	row.classList.remove("bg-primary-light/20", "ring-2", "ring-inset", "ring-primary/40");
}`,
		Call:       templ.SafeScript(`__templ_switchToViewMode_ff1e`, rowID),
		CallInline: templ.SafeScriptInline(`__templ_switchToViewMode_ff1e`, rowID),
	}
}

